const payload = $input.first().json;

const action = payload.action || '';
if (action !== 'published') return [];

const release = payload.release || {};
const repo    = payload.repository || {};

const rawBody     = release.body    || 'No changelog provided.';
const version     = release.tag_name || 'v0.0.0';
const releaseName = release.name    || version;
const releaseUrl  = release.html_url || '';
const author      = release.author?.login || 'the team';
const publishedAt = release.published_at  || new Date().toISOString();
const repoName    = repo.full_name || repo.name || 'Product';

const lines = rawBody.split('\n').map(l => l.trim()).filter(Boolean);
const features     = [];
const fixes        = [];
const improvements = [];
const other        = [];
let currentSection = 'other';

for (const line of lines) {
  const lower = line.toLowerCase();
  if (lower.match(/^##?#?\s*(feat|new)/))  { currentSection = 'features';     continue; }
  if (lower.match(/^##?#?\s*(fix|bug)/))   { currentSection = 'fixes';         continue; }
  if (lower.match(/^##?#?\s*(impr|chan|upd|perf)/)) { currentSection = 'improvements'; continue; }
  if (line.startsWith('-') || line.startsWith('*') || line.startsWith('\u2022')) {
    const clean = line.replace(/^[-*\u2022]\s*/, '').trim();
    if (!clean) continue;
    if (currentSection === 'features')          features.push(clean);
    else if (currentSection === 'fixes')        fixes.push(clean);
    else if (currentSection === 'improvements') improvements.push(clean);
    else other.push(clean);
  }
}

const plainChangelog = rawBody
  .replace(/#{1,6}\s*/g, '')
  .replace(/[*_`~]/g, '')
  .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1')
  .replace(/\n{3,}/g, '\n\n')
  .trim()
  .substring(0, 1500);

const safeVersion = version.replace(/[^a-zA-Z0-9._-]/g, '_');
const releaseDate = new Date(publishedAt).toLocaleDateString('en-US', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

return [{
  json: {
    version,
    releaseName,
    releaseUrl,
    author,
    releaseDate,
    repoName,
    plainChangelog,
    features,
    fixes,
    improvements,
    other,
    safeVersion,
    totalChanges: features.length + fixes.length + improvements.length + other.length,
    audioFilename: 'release-' + safeVersion + '.mp3'
  }
}];

