const script      = $input.first().json.output || '';
const releaseData = $('2. Code — Parse Release Changelog').first().json;

if (!script || script.trim().length < 20) {
  throw new Error('AI returned empty or too short script. Check your OpenAI credentials.');
}

return [{
  json: {
    ...releaseData,
    spokenScript: script.trim()
  }
}];

const driveFileId = $('6. Google Drive — Save MP3 File').first().json.id || '';
const driveItem   = $('6. Google Drive — Save MP3 File').first().json;
const releaseData = $('4. Code — Extract Script Text').first().json;

if (!driveFileId) throw new Error('Google Drive did not return a file ID.');

const audioUrl    = 'https://drive.google.com/file/d/' + driveFileId + '/view?usp=sharing';
const downloadUrl = 'https://drive.google.com/uc?export=download&id=' + driveFileId;

return [{
  json: {
    ...releaseData,
    driveFileId,
    audioUrl,
    downloadUrl,
    driveWebViewLink: driveItem.webViewLink || audioUrl
  }
}];

const rows        = $input.first().json.subscriberRows || [];
const releaseData = $('8. Code — Store Drive URL and Release Data').first().json;

const bccList = rows
  .map(row => row.Email || row.email || '')
  .filter(Boolean)
  .join(',');

if (!bccList) throw new Error('No subscribers found in Google Sheet. Add emails to the Subscribers tab.');

const makeRows = (items, tag) => items.map(i =>
  '<tr><td style="padding:8px 0;font-size:14px;color:#2d2d2d;border-bottom:1px solid #f0f0f0;"><strong style="color:#667eea;">' + tag + '</strong> ' + i + '</td></tr>'
).join('');

const featureRows = makeRows(releaseData.features     || [], '[New]');
const fixRows     = makeRows(releaseData.fixes        || [], '[Fix]');
const improvRows  = makeRows(releaseData.improvements || [], '[Improved]');
const otherRows   = makeRows(releaseData.other        || [], '[Note]');
const allRows     = featureRows + fixRows + improvRows + otherRows;

const changelogSection = allRows
  ? '<table style="width:100%;border-collapse:collapse;">' + allRows + '</table>'
  : '<p style="font-size:14px;color:#555;line-height:1.6;">' + releaseData.plainChangelog.substring(0, 400) + '...</p>';

const emailSubject = '[' + releaseData.version + '] ' + releaseData.releaseName + ' — Listen to the Update';

const htmlBody = '<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head>' +
'<body style="margin:0;padding:0;background:#f4f6fb;font-family:Arial,sans-serif;">' +
'<table width="100%" cellpadding="0" cellspacing="0"><tr><td align="center" style="padding:40px 20px;">' +
'<table width="600" cellpadding="0" cellspacing="0" style="background:#fff;border-radius:12px;overflow:hidden;box-shadow:0 2px 12px rgba(0,0,0,0.08);">' +

'<tr><td style="background:linear-gradient(135deg,#667eea 0%,#764ba2 100%);padding:36px 40px;">' +
'<h1 style="margin:0;color:#fff;font-size:24px;font-weight:700;">Product Update</h1>' +
'<p style="margin:8px 0 0;color:rgba(255,255,255,0.85);font-size:14px;">' + releaseData.releaseName + ' &middot; ' + releaseData.releaseDate + '</p>' +
'</td></tr>' +

'<tr><td style="padding:28px 40px;background:#f9f6ff;text-align:center;">' +
'<p style="margin:0 0 10px;color:#764ba2;font-size:12px;font-weight:600;text-transform:uppercase;letter-spacing:1px;">Listen to this release</p>' +
'<a href="' + releaseData.audioUrl + '" style="display:inline-block;background:#667eea;color:#fff;text-decoration:none;padding:14px 36px;border-radius:8px;font-size:15px;font-weight:600;">Listen Now</a>' +
'<br><br><p style="margin:0;font-size:12px;color:#999;">60-90 second audio summary of what changed</p>' +
'</td></tr>' +

'<tr><td style="padding:32px 40px;">' +
'<h2 style="margin:0 0 16px;color:#1a1a2e;font-size:18px;">What is new in ' + releaseData.version + '</h2>' +
changelogSection +
'</td></tr>' +

'<tr><td style="padding:0 40px 32px;text-align:center;">' +
'<a href="' + releaseData.releaseUrl + '" style="display:inline-block;border:2px solid #667eea;color:#667eea;text-decoration:none;padding:11px 28px;border-radius:8px;font-size:14px;font-weight:600;">View Full Release Notes on GitHub</a>' +
'</td></tr>' +

'<tr><td style="background:#f4f6fb;padding:20px 40px;text-align:center;border-top:1px solid #eee;">' +
'<p style="margin:0;color:#999;font-size:12px;">You are receiving this because you subscribed to ' + releaseData.repoName + ' product updates.</p>' +
'</td></tr>' +

'</table></td></tr></table></body></html>';

return [{
  json: {
    ...releaseData,
    bccList,
    htmlBody,
    emailSubject,
    subscriberCount: rows.length
  }
}];
